# Terraform: enforce region at the module level
variable "location" {
  type        = string
  description = "Azure region for all resources in this deployment"
  default     = "eastus"

  validation {
    condition     = contains(["eastus", "westeurope", "uksouth"], var.location)
    error_message = "Deployment is only permitted in approved regions: eastus, westeurope, uksouth"
  }
}

resource "azurerm_resource_group" "main" {
  name     = "prod-rg"
  location = var.location  # All resources inherit this variable
}

resource "azurerm_virtual_network" "main" {
  name                = "prod-vnet"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name
  address_space       = ["10.0.0.0/16"]
}

{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
  "contentVersion": "1.0.0.0",
  "parameters": {
    "location": {
      "type": "string",
      "defaultValue": "[resourceGroup().location]",
      "allowedValues": ["eastus", "westeurope", "uksouth"],
      "metadata": {
        "description": "Azure region — must be in the approved list for data residency compliance"
      }
    }
  },
  "resources": [
    {
      "type": "Microsoft.Storage/storageAccounts",
      "apiVersion": "2023-01-01",
      "name": "prodstgaccount",
      "location": "[parameters('location')]",
      "sku": { "name": "Standard_ZRS" },
      "kind": "StorageV2"
    }
  ]
}
